// ============================================
// FILTRUJ TYLKO NIESYNCHRONIZOWANE WIERSZE
// ============================================

const row = item.json;

// Pomiń jeśli już zsynchronizowano i nie ma zmian
const synced = (row['Zsynchronizowano'] || '').toString().toUpperCase();
const clickupId = row['ClickUp_ID'] || '';
const nazwaZadania = row['Nazwa Zadania'] || '';

// Pomiń puste wiersze
if (!nazwaZadania.trim()) {
  return null; // null = pomiń ten item
}

// Przetwórz wiersze:
// - NIE = nowy task do utworzenia
// - AKTUALIZUJ = zaktualizuj istniejący
// - TAK = już ok, pomijamy
if (synced === 'TAK' && clickupId) {
  return null; // już zsynchronizowany
}

// Mapowanie osoby na ID assignee w ClickUp
const assigneeMap = {
  'Maciek':    'CLICKUP_USER_ID_MACIEK',
  'Wojtek':    'CLICKUP_USER_ID_WOJTEK',
  'Agnieszka': 'CLICKUP_USER_ID_AGNIESZKA'
};

// Mapowanie statusu
const statusMap = {
  'Nowe':      'nowe',
  'W toku':    'w realizacji',
  'Czeka':     'czeka na akceptacje',
  'Gotowe':    'gotowe',
  'Anulowane': 'anulowane'
};

// Mapowanie priorytetu
const priorityMap = {
  'Pilny':   1,
  'Wysoki':  2,
  'Średni':  3,
  'Niski':   4
};

// Konwertuj deadline na timestamp
let deadlineTs = null;
if (row['Deadline']) {
  const d = new Date(row['Deadline']);
  if (!isNaN(d.getTime())) {
    deadlineTs = d.getTime();
  }
}

return {
  json: {
    // Dane z Sheets
    rowId:          row['ID'] || '',
    nazwaZadania:   nazwaZadania,
    klient:         row['Klient'] || '',
    przypisz_do:    row['Przypisz Do'] || '',
    assigneeId:     assigneeMap[row['Przypisz Do']] || null,
    status:         statusMap[row['Status']] || 'nowe',
    statusOriginal: row['Status'] || 'Nowe',
    deadline:       row['Deadline'] || '',
    deadlineTs,
    budzet:         row['Budżet'] || '',
    priorytet:      priorityMap[row['Priorytet']] || 3,
    notatki:        row['Notatki'] || '',

    // Meta
    clickupId:      clickupId,
    action:         clickupId ? 'update' : 'create',

    // Zachowaj numer wiersza do aktualizacji
    rowNumber:      row.row_number || row['_rowNumber'] || null
  }
};

