const updatedTask = item.json;
const originalData = $('🔍 Filtruj i Przygotuj Dane').item.json;

return {
  json: {
    clickupTaskId: originalData.clickupId,
    rowId: originalData.rowId,
    nazwaZadania: originalData.nazwaZadania,
    action: 'updated',
    newStatus: originalData.status
  }
};

// ============================================
// WALIDUJ I PRZYGOTUJ DANE POSTA
// ============================================

const row = $input.item.json;

// Sprawdź wymagane pola
if (!row.DATA_PUBLIKACJI) {
  return [{ json: { skip: true, reason: 'Brak daty', row } }];
}

if (!row.TYTUL && !row.OPIS) {
  return [{ json: { skip: true, reason: 'Brak tytułu i opisu', row } }];
}

// Parsuj datę
const dateParts = row.DATA_PUBLIKACJI.split('-');
const publishDate = new Date(
  parseInt(dateParts[0]),
  parseInt(dateParts[1]) - 1,
  parseInt(dateParts[2])
);

// Timestamp dla ClickUp (milisekundy)
const dueDateTs = publishDate.getTime();

// Priorytet na podstawie daty
const daysUntil = Math.ceil((publishDate - new Date()) / (1000 * 60 * 60 * 24));
let priority = 3; // normal
if (daysUntil <= 1) priority = 1;  // urgent
else if (daysUntil <= 3) priority = 2; // high
else if (daysUntil <= 7) priority = 3; // normal
else priority = 4; // low

// Emoji dla typu posta
const typeEmoji = {
  'Post':      '📝',
  'Reels':     '🎬',
  'Stories':   '📸',
  'Karuzela':  '🎠',
  'Wideo':     '🎥'
};

const emoji = typeEmoji[row.TYP_POSTA] || '📌';

// Nazwa taska
const taskName = `${emoji} ${row.DATA_PUBLIKACJI} | ${row.PLATFORMA || 'Social'} | ${row.TYTUL || row.OPIS?.substring(0, 50)}`;

// Opis taska (markdown)
const description = [
  `## ${row.TYTUL || 'Post bez tytułu'}`,
  '',
  `**📅 Data publikacji:** ${row.DATA_PUBLIKACJI} (${row.DZIEN_TYGODNIA || ''})`,
  `**📱 Platforma:** ${row.PLATFORMA || 'Nie określono'}`,
  `**🎬 Typ:** ${row.TYP_POSTA || 'Post'}`,
  '',
  '---',
  '',
  '### 📝 Treść posta',
  row.OPIS || '_Brak treści_',
  '',
  row.CTA_LINK ? `### 🔗 CTA / Link\n${row.CTA_LINK}` : '',
  '',
  row.HASZTAGI ? `### #️⃣ Hasztagi\n${row.HASZTAGI}` : '',
  '',
  row.LINK_GRAFIKI ? `### 🖼️ Grafika\n${row.LINK_GRAFIKI}` : '⚠️ _Brak grafiki_',
  '',
  row.NOTATKI ? `### 📋 Notatki\n${row.NOTATKI}` : '',
  '',
  '---',
  `*ID arkusza: ${row.ID}*`
].filter(line => line !== '').join('\n');

return [{
  json: {
    skip: false,
    sheetId: row.ID,
    taskName,
    description,
    publishDate: row.DATA_PUBLIKACJI,
    dueDateTs,
    priority,
    daysUntil,
    platform: row.PLATFORMA || 'Social Media',
    postType: row.TYP_POSTA || 'Post',
    title: row.TYTUL || '',
    content: row.OPIS || '',
    cta: row.CTA_LINK || '',
    hashtags: row.HASZTAGI || '',
    imageLink: row.LINK_GRAFIKI || '',
    notes: row.NOTATKI || '',
    rowNumber: row._rowNumber || row.rowIndex
  }
}];

// Zapisz ClickUp Task ID z powrotem do Sheets
const clickupResponse = item.json;
const taskId = clickupResponse.id || '';
const taskUrl = clickupResponse.url || '';

return {
  json: {
    clickupTaskId: taskId,
    clickupTaskUrl: taskUrl,
    success: !!taskId
  }
};

// Log pominiętego wiersza
const data = $input.item.json;
console.log(`Pominięto: ${data.reason} | Row: ${JSON.stringify(data.row?.ID)}`);
return [{ json: { skipped: true, reason: data.reason } }];

// ============================================
// PARSUJ PIONOWĄ STRUKTURĘ PLANERA SOCIAL MEDIA
// ============================================
// Struktura:
//   - Każda PARZYSTA kolumna (col_2, col_4...) = 1 dzień LUB 1 platforma
//   - Nieparzyste kolumny = puste separatory
//   - row_number mapuje konkretne pola
//
// GDZIE ZMIENIĆ ID LISTY CLICKUP:
//   → Szukaj komentarza: // ⚙️ ZMIEŃ ID LISTY
// ============================================

const allRows = $input.all().map(r => r.json);

// ============================================
// MAPOWANIE WIERSZY po row_number
// ============================================
function getRowByNumber(rows, rowNum) {
  return rows.find(r => r.row_number === rowNum) || {};
}

const ROW_DATA = {
  data:       getRowByNumber(allRows, 5),   // daty
  tytul:      getRowByNumber(allRows, 6),   // tytuł posta
  typGrafiki: getRowByNumber(allRows, 7),   // grafiki/wideo/karuzela
  typPosta:   getRowByNumber(allRows, 8),   // Post/Reels/TikTok
  linkGrafiki:getRowByNumber(allRows, 11),  // link Google Drive
  opis:       getRowByNumber(allRows, 13),  // treść opisu
  cta:        getRowByNumber(allRows, 15),  // CTA/link
  hasztagi:   getRowByNumber(allRows, 17),  // hasztagi
  status:     getRowByNumber(allRows, 19),  // STATUS
  notatki:    getRowByNumber(allRows, 21),  // notatki
  feedback:   getRowByNumber(allRows, 23),  // feedback
  taskId:     getRowByNumber(allRows, 25),  // TASK_ID wartość ← wiersz 25
};

// ============================================
// ZNAJDŹ WSZYSTKIE KOLUMNY Z DANYMI
// Kolumny mają format: col_2, col_4, col_6...
// Pierwsza kolumna ma nazwę = nazwa miesiąca (np. "stycznia 2026")
// ============================================

// Znajdź klucz pierwszej kolumny danych (alias miesiąca)
const firstColKey = Object.keys(ROW_DATA.data).find(k => 
  k !== 'row_number' && 
  k !== 'col_1' && 
  ROW_DATA.data[k] !== '' &&
  !k.startsWith('col_')
);

// Zbuduj listę wszystkich kluczy kolumn (co 2: col_2, col_4, col_6...)
const allColKeys = [];

// Dodaj pierwszą kolumnę (alias)
if (firstColKey) allColKeys.push(firstColKey);

// Dodaj col_4, col_6... aż do col_80 (z krokiem 2)
for (let i = 4; i <= 80; i += 2) {
  allColKeys.push(`col_${i}`);
}

// ============================================
// MAPOWANIE STATUSÓW → ClickUp
// ⚙️ ZMIEŃ statusy jeśli inne w Twoim ClickUp
// ============================================
const STATUS_MAP = {
  'APPROVED':              'Zatwierdzone przez klienta',
  'WAITING FOR APPROVAL':  'Wyslane do klienta',
  'NEEDS EDITING':         'Poprawki zakonczone',
  'NEEDS EDIT':            'Poprawki zakonczone',
  'DRAFT':                 'Do zrobienia',
  'PUBLISHED':             'W realizacji',
  'REJECTED':              'Do zrobienia',
  'IN PROGRESS':           'W realizacji',
  'TO DO':                 'Do zrobienia',
};

function mapStatus(rawStatus) {
  if (!rawStatus) return 'Do zrobienia';
  const upper = rawStatus.toUpperCase().trim();
  return STATUS_MAP[upper] || 'Do zrobienia';
}

// ============================================
// PARSUJ DATĘ PL
// Format: "czwartek, stycznia 1, 2026"
// ============================================
const MONTHS_PL = {
  'stycznia':   0,  'lutego':  1,  'marca':     2,
  'kwietnia':   3,  'maja':    4,  'czerwca':   5,
  'lipca':      6,  'sierpnia':7,  'września':  8,
  'października':9, 'listopada':10,'grudnia':   11
};

function parseDatePL(dateStr) {
  if (!dateStr || typeof dateStr !== 'string') return null;
  try {
    // "czwartek, stycznia 1, 2026" lub "sobota, stycznia 3, 2026"
    const match = dateStr.match(/(\w+),\s+(\w+)\s+(\d{1,2}),?\s+(\d{4})/);
    if (match) {
      const monthName = match[2].toLowerCase();
      const day       = parseInt(match[3]);
      const year      = parseInt(match[4]);
      const monthNum  = MONTHS_PL[monthName];
      if (monthNum !== undefined) {
        return new Date(year, monthNum, day);
      }
    }
    // Fallback
    const d = new Date(dateStr);
    return isNaN(d.getTime()) ? null : d;
  } catch(e) {
    return null;
  }
}

// ============================================
// SPRAWDŹ CZY KOLUMNA MA DANE
// ============================================
function isDataColumn(colKey) {
  // Musi mieć datę LUB tytuł
  const hasDate  = !!ROW_DATA.data[colKey];
  const hasTitle = !!ROW_DATA.tytul[colKey];
  const hasOdpis = !!ROW_DATA.opis[colKey];
  return hasDate || hasTitle || hasOdpis;
}

// ============================================
// GŁÓWNA PĘTLA — zbierz posty
// ============================================
const posts = [];
let colIndex = 0;

for (const colKey of allColKeys) {
  // Pomiń puste kolumny
  if (!isDataColumn(colKey)) continue;

  const dateRaw    = ROW_DATA.data[colKey]       || '';
  const tytul      = ROW_DATA.tytul[colKey]      || '';
  const typGrafiki = ROW_DATA.typGrafiki[colKey] || '';
  const typPosta   = ROW_DATA.typPosta[colKey]   || 'Post';
  const linkGraf   = ROW_DATA.linkGrafiki[colKey]|| '';
  const opis       = ROW_DATA.opis[colKey]       || '';
  const cta        = ROW_DATA.cta[colKey]        || '';
  const hasztagi   = ROW_DATA.hasztagi[colKey]   || '';
  const statusRaw  = ROW_DATA.status[colKey]     || '';
  const notatki    = ROW_DATA.notatki[colKey]    || '';
  const feedback   = ROW_DATA.feedback[colKey]   || '';
  const taskId     = ROW_DATA.taskId[colKey]     || '';

  // Pomiń jeśli brak tytułu i opisu
  if (!tytul && !opis) continue;

  // Pomiń jeśli to nagłówek (wartość = "OPIS", "STATUS" itp.)
  const SKIP_VALUES = ['OPIS','STATUS','HASZTAGI','CTA/LINK','NOTATKI',
                       'FEEDBACK OD KLIENTA','LINK TO GOOGLE DRIVE/FULL IMAGE'];
  if (SKIP_VALUES.includes(tytul.toUpperCase())) continue;

  // Parsuj datę
  const postDateObj = parseDatePL(dateRaw);
  const postDateISO = postDateObj ? postDateObj.toISOString() : null;

  // Mapuj status
  const clickupStatus = mapStatus(statusRaw);

  // Wyczyść link (usuń "Link to Google Drive/full image" placeholder)
  const cleanLink = (linkGraf && !linkGraf.toLowerCase().includes('link to google')) 
    ? linkGraf.trim() 
    : '';

  // Numer porządkowy posta w miesiącu
  colIndex++;

  posts.push({
    // ── Identyfikatory ──────────────────────
    kolumna:        colKey,
    numerPosta:     colIndex,

    // ── Data ────────────────────────────────
    dataRaw:        dateRaw,
    postDate:       postDateISO,
    postDateLabel:  postDateObj 
      ? postDateObj.toLocaleDateString('pl-PL', { 
          weekday:'long', day:'numeric', month:'long', year:'numeric' 
        }) 
      : dateRaw,

    // ── Treść ───────────────────────────────
    tytul:          tytul,
    typGrafiki:     typGrafiki,
    typPosta:       typPosta,
    linkGrafiki:    cleanLink,
    opis:           opis,
    cta:            cta,
    hasztagi:       hasztagi,

    // ── Status ──────────────────────────────
    statusRaw:      statusRaw,
    clickupStatus:  clickupStatus,

    // ── Task ID ─────────────────────────────
    taskId:         taskId,
    juzMaTask:      !!taskId && taskId.length > 3,

    // ── Dodatkowe ───────────────────────────
    notatki:        notatki,
    feedback:       feedback,

    // ── Flagi ───────────────────────────────
    maLink:         !!cleanLink,
    maOpis:         !!opis,
    maTytul:        !!tytul,
    jestApproved:   statusRaw.toUpperCase() === 'APPROVED',
    czekaNaAkcept:  statusRaw.toUpperCase().includes('WAITING'),
    wymaga_poprawek:statusRaw.toUpperCase().includes('NEEDS'),
  });
}

// ============================================
// PODSUMOWANIE
// ============================================
console.log(`✅ Znaleziono ${posts.length} postów w planerze`);
console.log(`📋 Bez task ID: ${posts.filter(p => !p.juzMaTask).length}`);
console.log(`✅ Approved: ${posts.filter(p => p.jestApproved).length}`);
console.log(`⏳ Czeka na akceptację: ${posts.filter(p => p.czekaNaAkcept).length}`);
console.log(`✏️ Wymaga poprawek: ${posts.filter(p => p.wymaga_poprawek).length}`);

return posts.map(p => ({ json: p }));

