// ============================================
// GENERUJ NAZWĘ AKTUALNEGO ARKUSZA
// Format: STYCZEŃ CONTENT PLANNER
// ============================================

const MONTHS_PL = [
  'STYCZEŃ','LUTY','MARZEC','KWIECIEŃ',
  'MAJ','CZERWIEC','LIPIEC','SIERPIEŃ',
  'WRZESIEŃ','PAŹDZIERNIK','LISTOPAD','GRUDZIEŃ'
];

const now = new Date();
const currentMonth = MONTHS_PL[now.getMonth()];
const currentYear  = now.getFullYear();

// Nazwa arkusza którą szukamy
const sheetName = `${currentMonth} CONTENT PLANNER`;
// Alternatywne nazwy (na wypadek różnych formatów)
const sheetNameAlt1 = `${currentMonth} CONTENT CALENDAR`;
const sheetNameAlt2 = `${currentMonth} ${currentYear} CONTENT PLANNER`;

console.log(`Szukam arkusza: ${sheetName}`);

return [{
  json: {
    currentMonth,
    currentYear,
    sheetName,
    sheetNameAlt1,
    sheetNameAlt2,
    monthIndex: now.getMonth(),
    generatedAt: now.toISOString()
  }
}];

// ============================================
// FILTRUJ AKTYWNYCH KLIENTÓW
// Połącz z danymi miesiąca
// ============================================

const monthData = $('📅 Przygotuj Nazwę Miesiąca').first().json;
const clients   = $input.all().map(r => r.json);

// Filtruj tylko aktywnych
const activeClients = clients.filter(c => {
  const isActive = String(c.aktywny).toUpperCase();
  return isActive === 'TRUE' || isActive === '1' || isActive === 'TAK';
});

console.log(`Klientów łącznie: ${clients.length}`);
console.log(`Aktywnych: ${activeClients.length}`);

// Dodaj dane miesiąca do każdego klienta
return activeClients.map(client => ({
  json: {
    ...client,
    ...monthData,
    // Nadpisz sheetName jeśli klient ma własny format
    targetSheet: client.wlasny_format_arkusza || monthData.sheetName
  }
}));

// ============================================
// ZNAJDŹ WŁAŚCIWY ARKUSZ DLA KLIENTA
// ============================================

const clientData    = $('🔍 Filtruj Aktywnych Klientów').item.json;
const sheetsInfo    = item.json;

// Lista wszystkich arkuszy w spreadsheet
const sheets = sheetsInfo.sheets || [];
const sheetNames = sheets.map(s => s.properties?.title || '');

console.log(`Klient: ${clientData.nazwa}`);
console.log(`Dostępne arkusze: ${sheetNames.join(', ')}`);

// Szukaj arkusza dla bieżącego miesiąca
const targetNames = [
  clientData.targetSheet,
  clientData.sheetName,
  clientData.sheetNameAlt1,
  clientData.sheetNameAlt2,
  // Szukaj też po samym miesiącu (case insensitive)
  ...sheetNames.filter(n => 
    n.toUpperCase().includes(clientData.currentMonth) &&
    n.toUpperCase().includes('PLANNER')
  )
];

// Znajdź pierwsze dopasowanie
let foundSheet = null;
for (const target of targetNames) {
  if (!target) continue;
  const match = sheetNames.find(s => 
    s.toUpperCase() === target.toUpperCase()
  );
  if (match) {
    foundSheet = match;
    break;
  }
}

// Jeśli nie znaleziono — weź najnowszy CONTENT PLANNER
if (!foundSheet) {
  const plannerSheets = sheetNames
    .filter(n => n.toUpperCase().includes('PLANNER'))
    .sort();
  foundSheet = plannerSheets[plannerSheets.length - 1] || null;
  console.warn(`Nie znaleziono arkusza dla ${clientData.currentMonth}, używam: ${foundSheet}`);
}

if (!foundSheet) {
  return {
    json: {
      ...clientData,
      error: true,
      errorMsg: `Brak arkusza CONTENT PLANNER dla klienta ${clientData.nazwa}`,
      foundSheet: null
    }
  };
}

console.log(`✅ Znaleziono arkusz: ${foundSheet}`);

return {
  json: {
    ...clientData,
    error: false,
    foundSheet,
    allSheets: sheetNames
  }
};

// Pobierz dane arkusza przez API Sheets
// Przekaż parametry do następnego węzła
const data = item.json;

return {
  json: {
    spreadsheetId: data.spreadsheet_id,
    sheetName:     data.foundSheet,
    klientId:      data.klient_id,
    klientNazwa:   data.nazwa,
    clickupListaId:data.clickup_lista_id,
    currentMonth:  data.currentMonth,
    currentYear:   data.currentYear,
    // Zakres do pobrania A1:CB25 (25 wierszy, ~80 kolumn)
    range:         `'${data.foundSheet}'!A1:CB25`
  }
};

// ============================================
// PARSUJ DANE ARKUSZA I WYODRĘBNIJ POSTY
// ============================================

const clientMeta = $('⚙️ Przygotuj Parametry Odczytu').item.json;
const rawData    = item.json;

// Sheets API zwraca values jako tablicę tablic
const values = rawData.values || [];

// Zamień na obiekt z row_number
// values[0] = wiersz 1, values[1] = wiersz 2 itd.
function getRow(rowNum) {
  return values[rowNum - 1] || [];
}

// Pobierz wartość z wiersza i kolumny (0-indexed)
function getCell(rowNum, colIdx) {
  const row = getRow(rowNum);
  return (row[colIdx] || '').trim();
}

// ── Znajdź kolumny z datami (wiersz 5) ──────
// Kolumny z datami to te gdzie wartość zawiera rok
const dateRow = getRow(5);
const dataCols = []  // indeksy kolumn z datami

for (let i = 0; i < dateRow.length; i++) {
  const val = (dateRow[i] || '').trim();
  // Kolumna z datą jeśli zawiera rok (np. 2026)
  if (val.match(/202[0-9]/) && val.length > 5) {
    dataCols.push(i);
  }
}

console.log(`Klient: ${clientMeta.klientNazwa}`);
console.log(`Znaleziono kolumn z datami: ${dataCols.length}`);

// ── Parser daty PL ──────────────────────────
const MONTHS_PL = {
  'stycznia':0,'lutego':1,'marca':2,'kwietnia':3,
  'maja':4,'czerwca':5,'lipca':6,'sierpnia':7,
  'września':8,'października':9,'listopada':10,'grudnia':11
};

function parseDatePL(str) {
  if (!str) return null;
  const m = str.match(/(\w+),?\s+(\w+)\s+(\d{1,2}),?\s+(\d{4})/);
  if (m) {
    const mon = MONTHS_PL[m[2].toLowerCase()];
    if (mon !== undefined) {
      return new Date(parseInt(m[4]), mon, parseInt(m[3]));
    }
  }
  return null;
}

// ── Mapowanie statusów ──────────────────────
const STATUS_MAP = {
  'APPROVED':             'Zatwierdzone przez klienta',
  'WAITING FOR APPROVAL': 'Wyslane do klienta',
  'NEEDS EDITING':        'Poprawki zakonczone',
  'NEEDS EDIT':           'Poprawki zakonczone',
  'DRAFT':                'Do zrobienia',
  'IN PROGRESS':          'W realizacji',
};

function mapStatus(s) {
  return STATUS_MAP[s?.toUpperCase()?.trim()] || 'Do zrobienia';
}

// ── MAPOWANIE WIERSZY ───────────────────────
// (numery wierszy 1-indexed)
const ROWS = {
  data:        5,
  tytul:       6,
  typGrafiki:  7,
  typPosta:    8,
  linkGrafiki: 11,
  opis:        13,
  cta:         15,
  hasztagi:    17,
  status:      19,
  notatki:     21,
  feedback:    23,
  taskId:      25,  // ← TASK_ID wartości
};

// ── ZBIERZ POSTY ────────────────────────────
const posts = [];

for (const colIdx of dataCols) {
  const dateRaw    = getCell(ROWS.data,        colIdx);
  const tytul      = getCell(ROWS.tytul,       colIdx);
  const typGrafiki = getCell(ROWS.typGrafiki,  colIdx);
  const typPosta   = getCell(ROWS.typPosta,    colIdx) || 'Post';
  const linkGraf   = getCell(ROWS.linkGrafiki, colIdx);
  const opis       = getCell(ROWS.opis,        colIdx);
  const cta        = getCell(ROWS.cta,         colIdx);
  const hasztagi   = getCell(ROWS.hasztagi,    colIdx);
  const statusRaw  = getCell(ROWS.status,      colIdx);
  const notatki    = getCell(ROWS.notatki,     colIdx);
  const feedback   = getCell(ROWS.feedback,    colIdx);
  const taskId     = getCell(ROWS.taskId,      colIdx);

  // Pomiń jeśli brak treści
  if (!tytul && !opis) continue;

  // Pomiń nagłówki
  const SKIP = ['OPIS','STATUS','HASZTAGI','CTA/LINK','NOTATKI',
                'FEEDBACK OD KLIENTA','LINK TO GOOGLE DRIVE/FULL IMAGE'];
  if (SKIP.includes(tytul.toUpperCase())) continue;

  // Wyczyść placeholder linku
  const cleanLink = linkGraf.toLowerCase().includes('link to google') 
    ? '' : linkGraf;

  const postDateObj = parseDatePL(dateRaw);

  posts.push({
    // Identyfikatory
    klientId:       clientMeta.klientId,
    klientNazwa:    clientMeta.klientNazwa,
    clickupListaId: clientMeta.clickupListaId,
    spreadsheetId:  clientMeta.spreadsheetId,
    sheetName:      clientMeta.sheetName,
    colIdx,          // indeks kolumny (0-based) do zapisu task ID

    // Data
    dataRaw,
    postDate:       postDateObj?.toISOString() || null,
    postDateLabel:  postDateObj?.toLocaleDateString('pl-PL', {
      weekday:'long', day:'numeric', month:'long', year:'numeric'
    }) || dateRaw,
    dueTimestamp:   postDateObj ? postDateObj.getTime() : null,

    // Treść
    tytul,
    typGrafiki,
    typPosta,
    linkGrafiki: cleanLink,
    opis,
    cta,
    hasztagi,

    // Status
    statusRaw,
    clickupStatus: mapStatus(statusRaw),

    // Task ID
    taskId,
    juzMaTask: !!taskId && taskId.length > 3,

    // Dodatkowe
    notatki,
    feedback,

    // Flagi
    jestApproved:    statusRaw.toUpperCase() === 'APPROVED',
    czekaNaAkcept:   statusRaw.toUpperCase().includes('WAITING'),
    wymagaPoprawek:  statusRaw.toUpperCase().includes('NEEDS'),
  });
}

console.log(`✅ ${clientMeta.klientNazwa}: ${posts.length} postów`);
console.log(`  Nowych (bez task): ${posts.filter(p=>!p.juzMaTask).length}`);
console.log(`  Approved: ${posts.filter(p=>p.jestApproved).length}`);

return posts.map(p => ({ json: p }));

// Wyciągnij ID nowego taska
const newTask    = item.json;
const postData   = $('🔍 Parsuj Posty Klienta').item.json;

// Konwertuj colIdx (0-based) na notację A1
function colIdxToLetter(idx) {
  let result = '';
  let n = idx + 1;
  while (n > 0) {
    n--;
    result = String.fromCharCode(65 + (n % 26)) + result;
    n = Math.floor(n / 26);
  }
  return result;
}

const colLetter  = colIdxToLetter(postData.colIdx);
const cellAddr   = `${colLetter}25`;  // wiersz 25 = TASK_ID

console.log(`✅ Task ${newTask.id} → komórka ${cellAddr} (${postData.klientNazwa})`);

return {
  json: {
    newTaskId:      newTask.id,
    newTaskUrl:     newTask.url,
    cellAddress:    cellAddr,
    colLetter,
    spreadsheetId:  postData.spreadsheetId,
    sheetName:      postData.sheetName,
    klientNazwa:    postData.klientNazwa,
    tytul:          postData.tytul,
    // Range do zapisu w Sheets API
    writeRange:     `'${postData.sheetName}'!${cellAddr}`
  }
};

// Log błędu — arkusz nie znaleziony
const d = $input.first().json;
console.error(`BŁĄD: ${d.errorMsg}`);
return [{ json: { error: true, klient: d.nazwa, msg: d.errorMsg } }];

