// ============================================
// PRZYGOTUJ DANE KLIENTA + WYKRYJ NAZWĘ ARKUSZA
// ============================================

const client = $input.first().json;

// Pomiń nieaktywnych
const isActive = String(client.aktywny || '').toUpperCase();
if (isActive !== 'TRUE' && isActive !== '1' && isActive !== 'TAK') {
  return [{ json: { skip: true, klient: client.nazwa } }];
}

// Generuj nazwę miesiąca
const MONTHS_PL = [
  'STYCZEŃ','LUTY','MARZEC','KWIECIEŃ',
  'MAJ','CZERWIEC','LIPIEC','SIERPIEŃ',
  'WRZESIEŃ','PAŹDZIERNIK','LISTOPAD','GRUDZIEŃ'
];

const now       = new Date();
const monthName = MONTHS_PL[now.getMonth()];

// ── Format z kolumny lub domyślny ──────────
// Klient może mieć: "CONTENT PLANNER" lub "CONTENT CALENDAR"
const format    = (client.format_arkusza || 'CONTENT PLANNER').trim().toUpperCase();
const sheetName = `${monthName} ${format}`;

// Alternatywne nazwy na wypadek gdyby format był inny
const sheetNameAlt = format.includes('PLANNER')
  ? `${monthName} CONTENT CALENDAR`
  : `${monthName} CONTENT PLANNER`;

console.log(`Klient: ${client.nazwa}`);
console.log(`Szukam arkusza: ${sheetName} (alt: ${sheetNameAlt})`);

return [{
  json: {
    skip:            false,
    klientId:        client.klient_id,
    klientNazwa:     client.nazwa,
    spreadsheetId:   client.spreadsheet_id,
    clickupListaId:  client.clickup_lista_id,
    sheetName,
    sheetNameAlt,
    monthName,
    rok:             now.getFullYear()
  }
}];

// ============================================
// SPLIT ROWS — parsuj arkusz i wyodrębnij posty
// Zwraca osobny item dla każdego posta
// ============================================

const clientMeta = $('⚙️ Przygotuj Dane Klienta').first().json;
const sheetData  = $input.first().json;

// Sheets API zwraca values[row][col]
const values = sheetData.values || [];

function getCell(rowNum, colIdx) {
  // rowNum = 1-indexed, colIdx = 0-indexed
  const row = values[rowNum - 1] || [];
  return (row[colIdx] || '').toString().trim();
}

// ── MAPOWANIE WIERSZY (1-indexed) ──────────
const ROWS = {
  data:        5,
  tytul:       6,
  typGrafiki:  7,
  typPosta:    8,
  linkGrafiki: 11,
  opis:        13,
  cta:         15,
  hasztagi:    17,
  status:      19,
  notatki:     21,
  feedback:    23,
  taskId:      25,
};

// ── ZNAJDŹ KOLUMNY Z DATAMI ─────────────────
// Wiersz 5 zawiera daty — szukamy kolumn gdzie jest rok 202x
const dateRow  = values[ROWS.data - 1] || [];
const dataCols = [];

for (let i = 0; i < dateRow.length; i++) {
  const val = (dateRow[i] || '').toString().trim();
  if (val.match(/\b202\d\b/) && val.length > 5) {
    dataCols.push(i);
  }
}

console.log(`${clientMeta.klientNazwa}: ${dataCols.length} kolumn z datami`);

// ── PARSER DATY PL ──────────────────────────
const MONTHS_PL = {
  'stycznia':0,'lutego':1,'marca':2,'kwietnia':3,
  'maja':4,'czerwca':5,'lipca':6,'sierpnia':7,
  'września':8,'października':9,'listopada':10,'grudnia':11
};

function parseDatePL(str) {
  if (!str) return null;
  try {
    const m = str.match(/(\w+),?\s+(\w+)\s+(\d{1,2}),?\s+(\d{4})/);
    if (m) {
      const mon = MONTHS_PL[m[2].toLowerCase()];
      if (mon !== undefined) {
        return new Date(parseInt(m[4]), mon, parseInt(m[3]));
      }
    }
  } catch(e) {}
  return null;
}

// ── MAPOWANIE STATUSÓW ──────────────────────
const STATUS_MAP = {
  'APPROVED':             'Zatwierdzone przez klienta',
  'WAITING FOR APPROVAL': 'Wyslane do klienta',
  'NEEDS EDITING':        'Poprawki zakonczone',
  'NEEDS EDIT':           'Poprawki zakonczone',
  'DRAFT':                'Do zrobienia',
  'IN PROGRESS':          'W realizacji',
  'PUBLISHED':            'W realizacji',
};

function mapStatus(s) {
  if (!s) return 'Do zrobienia';
  return STATUS_MAP[s.toUpperCase().trim()] || 'Do zrobienia';
}

// ── KONWERSJA colIdx → litera kolumny ───────
function colIdxToLetter(idx) {
  let result = '';
  let n = idx + 1;
  while (n > 0) {
    n--;
    result = String.fromCharCode(65 + (n % 26)) + result;
    n = Math.floor(n / 26);
  }
  return result;
}

// ── POMIŃ WARTOŚCI NAGŁÓWKOWE ───────────────
const SKIP_VALS = [
  'OPIS','STATUS','HASZTAGI','CTA/LINK','NOTATKI',
  'FEEDBACK OD KLIENTA','LINK TO GOOGLE DRIVE/FULL IMAGE',
  'TASK_ID','TASK ID'
];

// ── ZBIERZ POSTY ────────────────────────────
const posts = [];

for (const colIdx of dataCols) {
  const dataRaw    = getCell(ROWS.data,        colIdx);
  const tytul      = getCell(ROWS.tytul,       colIdx);
  const typGrafiki = getCell(ROWS.typGrafiki,  colIdx);
  const typPostaR  = getCell(ROWS.typPosta,    colIdx);
  const linkGraf   = getCell(ROWS.linkGrafiki, colIdx);
  const opis       = getCell(ROWS.opis,        colIdx);
  const cta        = getCell(ROWS.cta,         colIdx);
  const hasztagi   = getCell(ROWS.hasztagi,    colIdx);
  const statusRaw  = getCell(ROWS.status,      colIdx);
  const notatki    = getCell(ROWS.notatki,     colIdx);
  const feedback   = getCell(ROWS.feedback,    colIdx);
  const taskId     = getCell(ROWS.taskId,      colIdx);

  // Pomiń puste
  if (!tytul && !opis) continue;

  // Pomiń nagłówki
  if (SKIP_VALS.includes(tytul.toUpperCase())) continue;

  // Wyczyść placeholder linka
  const cleanLink = linkGraf.toLowerCase().includes('link to google')
    ? '' : linkGraf;

  // Parsuj datę
  const postDateObj  = parseDatePL(dataRaw);
  const postDateISO  = postDateObj ? postDateObj.toISOString() : null;
  const dueTimestamp = postDateObj ? postDateObj.getTime() : null;

  // Litera kolumny do zapisu task ID
  const colLetter  = colIdxToLetter(colIdx);
  const writeRange = `'${clientMeta.sheetName}'!${colLetter}25`;

  posts.push({
    // ── Klient ─────────────────────────────
    klientId:       clientMeta.klientId,
    klientNazwa:    clientMeta.klientNazwa,
    clickupListaId: clientMeta.clickupListaId,
    spreadsheetId:  clientMeta.spreadsheetId,
    sheetName:      clientMeta.sheetName,

    // ── Lokalizacja w arkuszu ───────────────
    colIdx,
    colLetter,
    writeRange,

    // ── Data ───────────────────────────────
    dataRaw,
    postDate:      postDateISO,
    postDateLabel: postDateObj
      ? postDateObj.toLocaleDateString('pl-PL', {
          weekday:'long', day:'numeric',
          month:'long',  year:'numeric'
        })
      : dataRaw,
    dueTimestamp,

    // ── Treść ──────────────────────────────
    tytul,
    typGrafiki,
    typPosta:    typPostaR || 'Post',
    linkGrafiki: cleanLink,
    opis,
    cta,
    hasztagi,

    // ── Status ─────────────────────────────
    statusRaw,
    clickupStatus: mapStatus(statusRaw),

    // ── Task ID ────────────────────────────
    taskId,
    juzMaTask: !!taskId && taskId.length > 3,

    // ── Dodatkowe ──────────────────────────
    notatki,
    feedback,

    // ── Flagi ──────────────────────────────
    jestApproved:   statusRaw.toUpperCase() === 'APPROVED',
    czekaNaAkcept:  statusRaw.toUpperCase().includes('WAITING'),
    wymagaPoprawek: statusRaw.toUpperCase().includes('NEEDS'),
  });
}

console.log(`${clientMeta.klientNazwa}: ${posts.length} postów do przetworzenia`);

return posts.map(p => ({ json: p }));

